import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Activity, Archive, LayoutDashboard, LogOut, Terminal, Cpu } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <nav style={navWrapper}>
      {/* ── Brand Section (Left) ── */}
      <Link to="/" style={brandLink}>
        <Cpu size={28} color="var(--accent-primary)" />
        <span style={brandText}>FINIFY_AI</span>
      </Link>

      {/* ── Navigation Links (Center) ── */}
      <div style={navLinks}>
        <Link to="/generate" style={linkStyle(isActive('/generate'))}>
          <LayoutDashboard size={20} /> GENERATE
        </Link>
        <Link to="/vault" style={linkStyle(isActive('/vault'))}>
          <Archive size={20} /> VAULT
        </Link>
        <Link to="/live" style={linkStyle(isActive('/live'))}>
          <Activity size={20} /> LIVE_PULSE
        </Link>
      </div>

      {/* ── User Actions (Right) ── */}
      <div style={userSection}>
        {user ? (
          <>
            <div style={userInfo}>
              <span style={userLabel}>SESSION_OPERATOR</span>
              <span style={userName}>{user.full_name?.toUpperCase()}</span>
            </div>
            <button onClick={handleLogout} style={logoutBtn}>
              <LogOut size={22} />
            </button>
          </>
        ) : (
          <Link to="/login" style={loginBtn}>INITIALIZE_CORE</Link>
        )}
      </div>
    </nav>
  );
};

/* --- Visual Styles (High Visibility) --- */
const navWrapper = {
  width: '100%',
  height: '80px', // Increased height
  background: '#0a0b0e',
  borderBottom: '2px solid #1a1d23', // Thicker border
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '0 2.5rem',
  boxSizing: 'border-box',
  position: 'sticky',
  top: 0,
  zIndex: 1000,
};

const brandLink = {
  display: 'flex',
  alignItems: 'center',
  gap: '15px',
  textDecoration: 'none'
};

const brandText = {
  fontSize: '1.4rem', // Big brand text
  fontWeight: 900,
  color: '#fff',
  letterSpacing: '0.2em',
  fontFamily: 'monospace'
};

const navLinks = {
  display: 'flex',
  gap: '3rem',
  alignItems: 'center'
};

const linkStyle = (active) => ({
  textDecoration: 'none',
  color: active ? 'var(--accent-primary)' : '#666',
  fontSize: '0.9rem', // Increased link size
  fontWeight: 900,
  letterSpacing: '0.15em',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  transition: 'all 0.2s ease',
  fontFamily: 'monospace',
  borderBottom: active ? '2px solid var(--accent-primary)' : '2px solid transparent',
  padding: '8px 0'
});

const userSection = {
  display: 'flex',
  alignItems: 'center',
  gap: '25px'
};

const userInfo = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'flex-end'
};

const userLabel = {
  fontSize: '0.6rem',
  color: 'var(--accent-primary)',
  fontWeight: 900,
  letterSpacing: '0.15em',
  marginBottom: '2px'
};

const userName = {
  fontSize: '1rem', // Big user name
  color: '#fff',
  fontWeight: 700,
  fontFamily: 'monospace'
};

const logoutBtn = {
  background: 'rgba(239, 68, 68, 0.1)',
  border: '1px solid rgba(239, 68, 68, 0.3)',
  color: '#ef4444',
  padding: '10px',
  borderRadius: '10px',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  transition: 'all 0.2s ease'
};

const loginBtn = {
  background: 'var(--accent-primary)',
  color: '#000',
  padding: '10px 20px',
  borderRadius: '8px',
  textDecoration: 'none',
  fontSize: '0.85rem',
  fontWeight: 900,
  fontFamily: 'monospace'
};

export default Navbar;
